module RefModule(  
    input wire clk,  
    input wire reset_signal,  
    input wire [3:0] timeout_period,  
    output reg timeout  
);  
    reg [3:0] unused_counter;  

    always @(posedge clk) begin  
        if (reset_signal) begin  
            unused_counter <= 0;  
            timeout <= 0;  
        end else if (unused_counter < timeout_period) begin  
            unused_counter <= unused_counter + 1;  
            timeout <= 0;  
        end else begin  
            timeout <= 1;  
        end  
    end  
endmodule
